mapper.select:
SELECT EXISTS(
    SELECT 1
    FROM pq_feature
    WHERE feature_code = #{featureCode}
)

SELECT EXISTS(
    SELECT 1
    FROM pq_feature
    WHERE feature_name = #{featureName}
)

SELECT EXISTS(
    SELECT 1
    FROM pq_feature
    WHERE feature_name = #{featureName}
      AND id != #{id}
)

mapper.update:
UPDATE pq_feature
SET feature_code = #{featureCode}
WHERE id = #{id}

UPDATE pq_feature
SET feature_name = #{featureName},
    sort_no = #{sortNo}
WHERE id = #{id}

UPDATE pq_feature
SET status = #{status}
WHERE id = #{id}
